import React, { useState, useEffect } from "react";
import axios from "axios";
import { toast, ToastContainer } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
import "./CategoryManager.css";

const API_BASE = "http://localhost:7000/api/categories";

const CategoryManager = () => {
  const [name, setName] = useState("");
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(false);
  const [editingId, setEditingId] = useState(null);

  // ✅ Fetch all categories
  const fetchCategories = async () => {
    try {
      const res = await axios.get(API_BASE);
      setCategories(res.data.categories);
    } catch (err) {
      toast.error("Failed to load categories");
    }
  };

  useEffect(() => {
    fetchCategories();
  }, []);

  // ✅ Add / Update Category
  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!name.trim()) {
      return toast.warn("Please enter a category name");
    }

    try {
      setLoading(true);

      if (editingId) {
        // Update category
        const res = await axios.put(`${API_BASE}/${editingId}`, { name });
        toast.success(res.data.message);
      } else {
        // Create new category
        const res = await axios.post(API_BASE, { name });
        toast.success(res.data.message);
      }

      setName("");
      setEditingId(null);
      fetchCategories();
    } catch (err) {
      toast.error(err.response?.data?.message || "Error saving category");
    } finally {
      setLoading(false);
    }
  };

  // ✅ Edit handler
  const handleEdit = (cat) => {
    setName(cat.name);
    setEditingId(cat._id);
  };

  // ✅ Delete handler
  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this category?")) {
      try {
        await axios.delete(`${API_BASE}/${id}`);
        toast.success("Category deleted successfully");
        fetchCategories();
      } catch (err) {
        toast.error("Error deleting category");
      }
    }
  };

  return (
    <div className="category-container">
      <h2>Category Manager</h2>

      <form className="category-form" onSubmit={handleSubmit}>
        <input
          type="text"
          placeholder="Enter category name"
          value={name}
          onChange={(e) => setName(e.target.value)}
        />
        <button type="submit" disabled={loading}>
          {loading
            ? "Saving..."
            : editingId
            ? "Update Category"
            : "Add Category"}
        </button>
        {editingId && (
          <button
            type="button"
            className="cancel-btn"
            onClick={() => {
              setEditingId(null);
              setName("");
            }}
          >
            Cancel
          </button>
        )}
      </form>

      <div className="category-list">
        <table>
          <thead>
            <tr>
              <th>#</th>
              <th>Category Name</th>
              <th>Created At</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {categories.length > 0 ? (
              categories.map((cat, index) => (
                <tr key={cat._id}>
                  <td>{index + 1}</td>
                  <td>{cat.name}</td>
                  <td>{new Date(cat.createdAt).toLocaleString()}</td>
                  <td>
                    <button
                      className="edit-btn"
                      onClick={() => handleEdit(cat)}
                    >
                      Edit
                    </button>
                    <button
                      className="delete-btn"
                      onClick={() => handleDelete(cat._id)}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="4" style={{ textAlign: "center" }}>
                  No categories found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      <ToastContainer position="top-right" autoClose={2000} />
    </div>
  );
};

export default CategoryManager;
